module RefModule(CLK,POSROTAF,ROTBF,EV,IZ);input CLK,ROTBF,POSROTAF;
	output reg EV,IZ;



	  wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always@(posedge CLK or posedge dbg_halt)
		begin
			if(POSROTAF)
				begin
					EV=1;
					IZ=ROTBF;
				end
			else
				begin
					EV=0;
					IZ=IZ;
				end
		end

endmodule
